+  const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf8')) as PackageJson;
+  if (!pkg.version) {
+    throw new Error(`package.json at ${pkgPath} is missing a version`);
+  }
+  return pkg.version;
+}
